import React, { useState, useEffect } from 'react';
import { apiClient } from '../api/client';

export default function AssetDirectory() {
  const [assets, setAssets] = useState([]);
  const [loading, setLoading] = useState(true);

  const [search, setSearch] = useState('');

  useEffect(() => {
    fetchAssets();
  }, [search]);

  const fetchAssets = async () => {
    try {
      setLoading(true);
      const data = await apiClient.get(`/assets?search=${encodeURIComponent(search)}`);
      setAssets(data.data || data || []);
    } catch (error) {
      console.error('Failed to fetch assets:', error);
      setAssets([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-content">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h1>Asset Directory</h1>
        <div style={{ display: 'flex', gap: '1rem' }}>
          <input 
            type="text" 
            className="form-control" 
            placeholder="Search assets..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <button className="btn btn-primary">Add New Asset</button>
        </div>
      </div>

      <div className="card">
        {loading ? (
          <p>Loading assets...</p>
        ) : (
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>Tag / ID</th>
                  <th>Name</th>
                  <th>Category</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {assets.length === 0 ? (
                  <tr>
                    <td colSpan="5" style={{ textAlign: 'center' }}>No assets found</td>
                  </tr>
                ) : (
                  assets.map(asset => (
                    <tr key={asset.id}>
                      <td>{asset.asset_tag || asset.id}</td>
                      <td>{asset.name}</td>
                      <td>{asset.category?.name || 'N/A'}</td>
                      <td>
                        <span className={`badge badge-${asset.status === 'Active' ? 'success' : 'neutral'}`}>
                          {asset.status || 'Unknown'}
                        </span>
                      </td>
                      <td>
                        <button className="btn btn-secondary" style={{ padding: '0.25rem 0.5rem', fontSize: '0.75rem' }}>View</button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { apiClient } from '../api/client';

export default function Audits() {
  const [audits, setAudits] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    apiClient.get('/audit-cycles')
      .then(data => {
        setAudits(data.data || data || []);
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  }, []);

  return (
    <div className="page-content">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2>Audits</h2>
        <button className="btn btn-primary">Export Audits</button>
      </div>

      <div className="card">
        {loading && <p>Loading audits...</p>}
        {error && <p style={{ color: 'var(--danger)' }}>{error}</p>}
        
        {!loading && !error && (
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>Audit ID</th>
                  <th>Action</th>
                  <th>Entity</th>
                  <th>User</th>
                  <th>Timestamp</th>
                </tr>
              </thead>
              <tbody>
                {audits.length === 0 ? (
                  <tr>
                    <td colSpan="5" style={{ textAlign: 'center' }}>No audits found</td>
                  </tr>
                ) : (
                  audits.map(audit => (
                    <tr key={audit.id}>
                      <td>{audit.id}</td>
                      <td>
                        <span className="badge badge-info">{audit.action}</span>
                      </td>
                      <td>{audit.entityType} ({audit.entityId})</td>
                      <td>{audit.user}</td>
                      <td>{new Date(audit.timestamp).toLocaleString()}</td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { apiClient } from '../api/client';

export default function Bookings() {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  
  const [showForm, setShowForm] = useState(false);
  const [assetId, setAssetId] = useState('');
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [purpose, setPurpose] = useState('');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    fetchBookings();
  }, []);

  const fetchBookings = () => {
    setLoading(true);
    apiClient.get('/bookings')
      .then(data => {
        setBookings(data.data || data || []);
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  };

  const handleCreateBooking = async () => {
    if (!assetId || !startTime || !endTime) return;
    try {
      setSubmitting(true);
      await apiClient.post('/bookings', {
        asset_id: parseInt(assetId),
        start_time: startTime,
        end_time: endTime,
        purpose: purpose
      });
      setShowForm(false);
      setAssetId('');
      setStartTime('');
      setEndTime('');
      setPurpose('');
      fetchBookings();
    } catch (err) {
      console.error('Failed to create booking:', err);
      alert('Error: ' + (err.message || 'Failed to create booking'));
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="page-content">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <h2>Bookings</h2>
        <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
          {showForm ? 'Cancel' : 'New Booking'}
        </button>
      </div>

      {showForm && (
        <div className="card" style={{ marginBottom: '2rem' }}>
          <h3>Create New Booking</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginTop: '1rem' }}>
            <div className="form-group">
              <label>Asset ID</label>
              <input type="number" className="form-control" value={assetId} onChange={e => setAssetId(e.target.value)} />
            </div>
            <div className="form-group">
              <label>Purpose</label>
              <input type="text" className="form-control" value={purpose} onChange={e => setPurpose(e.target.value)} />
            </div>
            <div className="form-group">
              <label>Start Time</label>
              <input type="datetime-local" className="form-control" value={startTime} onChange={e => setStartTime(e.target.value)} />
            </div>
            <div className="form-group">
              <label>End Time</label>
              <input type="datetime-local" className="form-control" value={endTime} onChange={e => setEndTime(e.target.value)} />
            </div>
          </div>
          <button className="btn btn-primary" style={{ marginTop: '1rem' }} onClick={handleCreateBooking} disabled={submitting}>
            {submitting ? 'Submitting...' : 'Submit Booking'}
          </button>
        </div>
      )}

      <div className="card">
        {loading && <p>Loading bookings...</p>}
        {error && <p style={{ color: 'var(--danger)' }}>{error}</p>}
        
        {!loading && !error && (
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Asset ID</th>
                  <th>Start Time</th>
                  <th>End Time</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {bookings.length === 0 ? (
                  <tr>
                    <td colSpan="5" style={{ textAlign: 'center' }}>No bookings found</td>
                  </tr>
                ) : (
                  bookings.map(booking => (
                    <tr key={booking.id}>
                      <td>{booking.id}</td>
                      <td>{booking.asset_id}</td>
                      <td>{new Date(booking.start_time).toLocaleString()}</td>
                      <td>{new Date(booking.end_time).toLocaleString()}</td>
                      <td>
                        <span className={`badge badge-${booking.status === 'confirmed' ? 'success' : booking.status === 'pending' ? 'warning' : 'neutral'}`}>
                          {booking.status || 'unknown'}
                        </span>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { apiClient } from '../api/client';

export default function Maintenance() {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [assetId, setAssetId] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState('Medium');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = async () => {
    try {
      setLoading(true);
      const data = await apiClient.get('/maintenance-requests');
      setTasks(data.data || data || []);
    } catch (error) {
      console.error('Failed to fetch maintenance tasks:', error);
      setTasks([]);
    } finally {
      setLoading(false);
    }
  };

  const handleLogTask = async () => {
    if (!assetId || !description) return;
    try {
      setSubmitting(true);
      await apiClient.post('/maintenance-requests', {
        asset_id: parseInt(assetId),
        issue_description: description,
        priority: priority
      });
      setAssetId('');
      setDescription('');
      fetchTasks();
    } catch (error) {
      console.error('Failed to log task:', error);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="page-content">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h1>Maintenance Records</h1>
      </div>

      <div className="card" style={{ marginBottom: '2rem' }}>
        <h2>Log New Task</h2>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '1rem', marginTop: '1rem' }}>
          <div className="form-group">
            <label>Asset ID</label>
            <input type="text" className="form-control" placeholder="Asset ID" value={assetId} onChange={e => setAssetId(e.target.value)} />
          </div>
          <div className="form-group">
            <label>Issue Description</label>
            <input type="text" className="form-control" placeholder="Describe the issue..." value={description} onChange={e => setDescription(e.target.value)} />
          </div>
          <div className="form-group">
            <label>Priority</label>
            <select className="form-control" value={priority} onChange={e => setPriority(e.target.value)}>
              <option value="Low">Low</option>
              <option value="Medium">Medium</option>
              <option value="High">High</option>
              <option value="Critical">Critical</option>
            </select>
          </div>
        </div>
        <button className="btn btn-primary" style={{ marginTop: '1rem' }} onClick={handleLogTask} disabled={submitting}>
          {submitting ? 'Submitting...' : 'Submit Task'}
        </button>
      </div>

      <div className="card">
        <h3>Maintenance History</h3>
        {loading ? (
          <p>Loading tasks...</p>
        ) : (
          <div className="table-container" style={{ marginTop: '1rem' }}>
            <table>
              <thead>
                <tr>
                  <th>Task ID</th>
                  <th>Asset ID</th>
                  <th>Description</th>
                  <th>Status</th>
                  <th>Cost</th>
                </tr>
              </thead>
              <tbody>
                {tasks.length === 0 ? (
                  <tr>
                    <td colSpan="5" style={{ textAlign: 'center' }}>No maintenance records found</td>
                  </tr>
                ) : (
                  tasks.map(task => (
                    <tr key={task.id}>
                      <td>{task.id}</td>
                      <td>{task.assetId}</td>
                      <td>{task.description}</td>
                      <td>
                        <span className={`badge badge-${task.status === 'Pending' ? 'warning' : 'success'}`}>
                          {task.status}
                        </span>
                      </td>
                      <td>${task.cost}</td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

const prisma = require('../../shared/prismaClient');

const create = async (req, res, next) => {
  try {
    const { name, category_id, serial_number, acquisition_date, acquisition_cost, condition, location, is_bookable, photo_url } = req.body;
    
    // Generate Asset Tag and Create Asset in a transaction
    const newAsset = await prisma.$transaction(async (tx) => {
      // Find the latest asset to increment the tag
      const lastAsset = await tx.asset.findFirst({
        orderBy: { id: 'desc' }
      });
      
      let nextNumber = 1;
      if (lastAsset && lastAsset.asset_tag.startsWith('AF-')) {
        const lastNumber = parseInt(lastAsset.asset_tag.replace('AF-', ''), 10);
        if (!isNaN(lastNumber)) {
          nextNumber = lastNumber + 1;
        }
      }
      
      const asset_tag = `AF-${String(nextNumber).padStart(4, '0')}`;
      
      const asset = await tx.asset.create({
        data: {
          asset_tag,
          name,
          category_id,
          serial_number,
          acquisition_date: acquisition_date ? new Date(acquisition_date) : null,
          acquisition_cost,
          condition,
          location,
          is_bookable: !!is_bookable,
          photo_url,
          status: 'Available'
        }
      });
      
      return asset;
    });

    res.status(201).json({ success: true, data: { asset: newAsset, asset_tag: newAsset.asset_tag }, error: null });
  } catch (err) {
    next(err);
  }
};

const list = async (req, res, next) => {
  try {
    const { status, category_id, department_id, search, page = 1, limit = 10, location } = req.query;
    
    const query = {
      where: {}
    };

    if (status) query.where.status = status;
    if (category_id) query.where.category_id = parseInt(category_id);
    if (location) query.where.location = location;

    if (search) {
      query.where.OR = [
        { name: { contains: search, mode: 'insensitive' } },
        { asset_tag: { contains: search, mode: 'insensitive' } },
        { serial_number: { contains: search, mode: 'insensitive' } }
      ];
    }

    if (department_id) {
      // Filter by current Allocation's department
      query.where.allocations = {
        some: {
          status: 'Active',
          holder_department_id: parseInt(department_id)
        }
      };
    }

    const skip = (parseInt(page) - 1) * parseInt(limit);
    query.skip = skip;
    query.take = parseInt(limit);
    
    const [assets, total] = await Promise.all([
      prisma.asset.findMany({ ...query, include: { category: true } }),
      prisma.asset.count({ where: query.where })
    ]);

    res.json({
      success: true,
      data: assets,
      meta: { total, page: parseInt(page), limit: parseInt(limit) },
      error: null
    });
  } catch (err) {
    next(err);
  }
};

const getById = async (req, res, next) => {
  try {
    const { id } = req.params;
    const asset = await prisma.asset.findUnique({
      where: { id: parseInt(id) },
      include: {
        category: true,
        allocations: {
          orderBy: { created_at: 'desc' },
          include: {
            holder_user: { select: { id: true, name: true, email: true } },
            holder_department: { select: { id: true, name: true } },
            allocator: { select: { id: true, name: true } }
          }
        },
        maintenance_requests: {
          orderBy: { created_at: 'desc' },
          include: {
            raiser: { select: { id: true, name: true } },
            approver: { select: { id: true, name: true } }
          }
        }
      }
    });

    if (!asset) {
      return res.status(404).json({ success: false, data: null, error: { code: 'NOT_FOUND', message: 'Asset not found' } });
    }

    const activeAllocation = asset.allocations.find(a => a.status === 'Active');
    let current_holder = null;
    if (activeAllocation) {
      if (activeAllocation.holder_user) {
        current_holder = { type: 'User', ...activeAllocation.holder_user };
      } else if (activeAllocation.holder_department) {
        current_holder = { type: 'Department', ...activeAllocation.holder_department };
      }
    }

    // Separate asset details from relations to match API contract
    const assetData = { ...asset };
    delete assetData.allocations;
    delete assetData.maintenance_requests;

    res.json({
      success: true,
      data: {
        asset: assetData,
        current_holder,
        allocation_history: asset.allocations,
        maintenance_history: asset.maintenance_requests
      },
      error: null
    });
  } catch (err) {
    next(err);
  }
};

const update = async (req, res, next) => {
  try {
    const { id } = req.params;
    const updates = req.body;
    
    // Prevent updating critical fields like asset_tag, status directly via this endpoint
    delete updates.asset_tag;
    delete updates.status;
    
    if (updates.acquisition_date) {
      updates.acquisition_date = new Date(updates.acquisition_date);
    }
    
    const asset = await prisma.asset.update({
      where: { id: parseInt(id) },
      data: updates
    });

    res.json({ success: true, data: { asset }, error: null });
  } catch (err) {
    next(err);
  }
};

module.exports = {
  create,
  list,
  getById,
  update
};

const prisma = require('../../shared/prismaClient');

exports.list = async (req, res) => {
  try {
    const reports = [
      { id: 1, name: 'Asset Utilization Report', type: 'PDF', generatedAt: new Date() },
      { id: 2, name: 'Maintenance Frequency Report', type: 'CSV', generatedAt: new Date() },
      { id: 3, name: 'Department Allocation Summary', type: 'PDF', generatedAt: new Date() },
      { id: 4, name: 'Booking Summary Report', type: 'Excel', generatedAt: new Date() }
    ];
    res.json({ success: true, data: reports, error: null });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Internal server error' });
  }
};

exports.utilization = async (req, res) => {
  try {
    const allocations = await prisma.allocation.groupBy({
      by: ['asset_id'],
      _count: { asset_id: true },
      orderBy: { _count: { asset_id: 'desc' } }
    });
    res.json({ data: allocations });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Internal server error' });
  }
};

exports.maintenanceFrequency = async (req, res) => {
  try {
    const results = await prisma.$queryRaw`
      SELECT a.category_id, COUNT(mr.id) as count
      FROM "MaintenanceRequest" mr
      JOIN "Asset" a ON mr.asset_id = a.id
      GROUP BY a.category_id
      ORDER BY count DESC
    `;
    
    const formatted = results.map(r => ({
      category_id: r.category_id,
      count: Number(r.count)
    }));

    res.json({ data: formatted });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Internal server error' });
  }
};

exports.departmentAllocation = async (req, res) => {
  try {
    const allocations = await prisma.allocation.groupBy({
      by: ['holder_department_id'],
      _count: { holder_department_id: true },
      where: { holder_department_id: { not: null } }
    });
    res.json({ data: allocations });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Internal server error' });
  }
};

exports.bookingSummary = async (req, res) => {
  try {
    const bookings = await prisma.booking.groupBy({
      by: ['asset_id'],
      _count: { asset_id: true }
    });
    res.json({ data: bookings });
  } catch (err) {
    console.error(err);
    res.status(500).json({ error: 'Internal server error' });
  }
};

const express = require('express');
const router = express.Router();
const reportController = require('./report.controller');
const authenticate = require('../../shared/authenticate');

router.get('/', authenticate, reportController.list);
router.get('/utilization', authenticate, reportController.utilization);
router.get('/maintenance-frequency', authenticate, reportController.maintenanceFrequency);
router.get('/department-allocation', authenticate, reportController.departmentAllocation);
router.get('/booking-summary', authenticate, reportController.bookingSummary);

module.exports = router;

